1	import mssql from "mssql";
2	
3	const sqlConfig = {
4	  user: process.env.DB_USER,
5	  password: process.env.DB_PASSWORD,
6	  database: process.env.DB_NAME,
7	  server: process.env.DB_SERVER || "",
8	  port: 1433,
9	  pool: {
10	    max: 10,
11	    min: 0,
12	    idleTimeoutMillis: 30000,
13	  },
14	  options: {
15	    encrypt: true, 
16	    trustServerCertificate: true, // Local dev/IP connections için
17	  },
18	};
19	
20	const poolPromise = new mssql.ConnectionPool(sqlConfig)
21	  .connect()
22	  .then((pool) => {
23	    console.log("MSSQL veritabanına başarıyla bağlanıldı.");
24	    return pool;
25	  })
26	  .catch((err) => {
27	    console.log("Veritabanı bağlantısı başarısız! Hata: ", err);
28	    throw err;
29	  });
30	
31	export default poolPromise;
