1	import { getServerSession } from "next-auth";
2	import { authOptions } from "@/lib/auth";
3	import NumuneKabulTable from "./NumuneKabulTable";
4	import styles from "@/app/styles/table.module.css";
5	
6	export const metadata = { title: "Numune Kabul" };
7	
8	export default async function NumuneKabulPage() {
9	  await getServerSession(authOptions);
10	
11	  return (
12	    <div className={styles.page} style={{ maxWidth: "none" }}>
13	      <div className={styles.pageHeader}>
14	        <div>
15	          <h1 className={styles.pageTitle}>Numune Kabul</h1>
16	          <p className={styles.pageSubtitle}>
17	            Laboratuvara kabul edilen numunelerin takibi ve yönetimi.
18	          </p>
19	        </div>
20	      </div>
21	      <NumuneKabulTable />
22	    </div>
23	  );
24	}
